module top_module(
    input [8:0] obf_doutb,
    output reg [2:0] mux_out
);always @(*) begin
    case(obf_doutb[2:0])
        3'b000: mux_out = obf_doutb[8:6];
        3'b001: mux_out = obf_doutb[5:3];
        3'b010: mux_out = obf_doutb[2:0];
        default: mux_out = 3'b0;
    endcase
end

endmodule
